import{_ as o,o as t,c as s,ai as i}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Reactions","description":"","frontmatter":{"summary":"Reaction semantics shared across channels","read_when":["Working on reactions in any channel"],"title":"Reactions"},"headers":[],"relativePath":"tools/reactions.md","filePath":"tools/reactions.md","lastUpdated":null}'),n={name:"tools/reactions.md"};function r(a,e,c,l,d,m){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="reaction-tooling" tabindex="-1"><a class="header-anchor" href="#reaction-tooling">#</a> Reaction tooling</h1><p>Shared reaction semantics across channels:</p><ul><li><code>emoji</code> is required when adding a reaction.</li><li><code>emoji=&quot;&quot;</code> removes the bot&#39;s reaction(s) when supported.</li><li><code>remove: true</code> removes the specified emoji when supported (requires <code>emoji</code>).</li></ul><p>Channel notes:</p><ul><li><strong>Discord/Slack</strong>: empty <code>emoji</code> removes all of the bot&#39;s reactions on the message; <code>remove: true</code> removes just that emoji.</li><li><strong>Google Chat</strong>: empty <code>emoji</code> removes the app&#39;s reactions on the message; <code>remove: true</code> removes just that emoji.</li><li><strong>Telegram</strong>: empty <code>emoji</code> removes the bot&#39;s reactions; <code>remove: true</code> also removes reactions but still requires a non-empty <code>emoji</code> for tool validation.</li><li><strong>WhatsApp</strong>: empty <code>emoji</code> removes the bot reaction; <code>remove: true</code> maps to empty emoji (still requires <code>emoji</code>).</li><li><strong>Signal</strong>: inbound reaction notifications emit system events when <code>channels.signal.reactionNotifications</code> is enabled.</li></ul>',5)])])}const u=o(n,[["render",r]]);export{h as __pageData,u as default};
